# C Project Makefile
# Standard build targets for development and production

# Compiler and flags
CC := gcc
CFLAGS := -Wall -Wextra -std=c99
DEBUGFLAGS := -g -O0
RELEASEFLAGS := -O2 -DNDEBUG
LDFLAGS :=

# Directories
SRCDIR := src
BUILDDIR := build
BINDIR := $(BUILDDIR)/bin
OBJDIR := $(BUILDDIR)/obj

# Project files
TARGET := $(BINDIR)/app
SOURCES := $(wildcard $(SRCDIR)/*.c)
OBJECTS := $(patsubst $(SRCDIR)/%.c,$(OBJDIR)/%.o,$(SOURCES))

# Default target
.PHONY: all
all: $(TARGET)

# Create build directories
$(BUILDDIR) $(BINDIR) $(OBJDIR):
	@mkdir -p $@

# Compile object files
$(OBJDIR)/%.o: $(SRCDIR)/%.c | $(OBJDIR)
	@echo "Compiling $<..."
	@$(CC) $(CFLAGS) $(DEBUGFLAGS) -c $< -o $@

# Link executable
$(TARGET): $(OBJECTS) | $(BINDIR)
	@echo "Linking $(TARGET)..."
	@$(CC) $(OBJECTS) $(LDFLAGS) -o $@
	@echo "Build complete: $(TARGET)"

# Debug build with symbols
.PHONY: debug
debug: DEBUGFLAGS := -g -O0
debug: clean all
	@echo "Debug build complete"

# Release build with optimization
.PHONY: release
release: DEBUGFLAGS := -O2 -DNDEBUG
release: clean all
	@mkdir -p $(BUILDDIR)/release
	@strip $(TARGET) -o $(BUILDDIR)/release/app
	@tar -czf $(BUILDDIR)/app-release.tar.gz -C $(BUILDDIR)/release app
	@echo "Release build complete: $(BUILDDIR)/app-release.tar.gz"

# Install target (requires root or appropriate permissions)
.PHONY: install
install: $(TARGET)
	@echo "Installing to /usr/local/bin/..."
	@install -D -m 755 $(TARGET) /usr/local/bin/app
	@echo "Installation complete"

# Run the application
.PHONY: run
run: $(TARGET)
	@echo "Running application..."
	@./$(TARGET)

# Clean build artifacts
.PHONY: clean
clean:
	@echo "Cleaning build artifacts..."
	@rm -rf $(BUILDDIR)
	@echo "Clean complete"

# Deep clean (removes all generated files)
.PHONY: distclean
distclean: clean
	@echo "Removing all generated files..."
	@find . -name "*.o" -delete
	@find . -name ".DS_Store" -delete

# Help target
.PHONY: help
help:
	@echo "Available targets:"
	@echo "  all       - Build the project (default)"
	@echo "  debug     - Build with debug symbols"
	@echo "  release   - Build optimized release version"
	@echo "  run       - Build and run the application"
	@echo "  install   - Install binary to /usr/local/bin/"
	@echo "  clean     - Remove build artifacts"
	@echo "  distclean - Remove all generated files"
	@echo "  help      - Display this help message"

# Build information
.PHONY: info
info:
	@echo "Build Configuration:"
	@echo "  Compiler: $(CC)"
	@echo "  CFLAGS: $(CFLAGS)"
	@echo "  Source files: $(SOURCES)"
	@echo "  Object files: $(OBJECTS)"
	@echo "  Target: $(TARGET)"

.SILENT: info help
